import Link from "next/link";
import Image from "next/image";
import {
  Facebook,
  Instagram,
  Youtube,
  Twitter,
  MapPin,
  Phone,
  Mail,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { CHURCH_INFO, SOCIAL_LINKS, FOOTER_LINKS } from "@/lib/constants";

const socialIcons: Record<string, React.ElementType> = {
  facebook: Facebook,
  instagram: Instagram,
  youtube: Youtube,
  twitter: Twitter,
};

export function Footer() {
  const year = new Date().getFullYear();

  return (
    <footer className="bg-[var(--bg-card)] border-t border-[var(--border)]">
      {/* Main footer grid */}
      <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 py-12 lg:py-16">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-6 gap-10 lg:gap-8">
          {/* Church info column (spans 2) */}
          <div className="lg:col-span-2">
            {/* Logo + name */}
            <Link href="/" className="inline-flex items-center gap-3 mb-4">
              <Image
                src="/logo.png"
                alt="Presbyterian Church of Ghana Logo"
                width={40}
                height={48}
                className="shrink-0"
              />
              <span className="font-[family-name:var(--font-heading)] text-lg font-bold text-[var(--text)]">
                Most Holy Trinity
              </span>
            </Link>

            <p className="text-sm text-[var(--text-muted)] leading-relaxed mb-6 max-w-sm">
              {CHURCH_INFO.tagline}. Join us for worship, community, and
              spiritual growth in Lashibi, Accra.
            </p>

            {/* Contact details */}
            <div className="space-y-2.5 text-sm text-[var(--text-muted)]">
              <div className="flex items-start gap-2.5">
                <MapPin size={16} className="shrink-0 mt-0.5 text-[var(--accent)]" />
                <a
                  href={CHURCH_INFO.address.mapUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="hover:text-[var(--text)] transition-colors"
                >
                  {CHURCH_INFO.address.formatted}
                </a>
              </div>
              <div className="flex items-center gap-2.5">
                <Phone size={16} className="shrink-0 text-[var(--accent)]" />
                <a
                  href={`tel:${CHURCH_INFO.phone.replace(/\s/g, "")}`}
                  className="hover:text-[var(--text)] transition-colors"
                >
                  {CHURCH_INFO.phone}
                </a>
              </div>
              <div className="flex items-center gap-2.5">
                <Mail size={16} className="shrink-0 text-[var(--accent)]" />
                <a
                  href={`mailto:${CHURCH_INFO.email}`}
                  className="hover:text-[var(--text)] transition-colors"
                >
                  {CHURCH_INFO.email}
                </a>
              </div>
            </div>

            {/* Social links */}
            <div className="flex items-center gap-3 mt-6">
              {SOCIAL_LINKS.map((social) => {
                const Icon = socialIcons[social.platform];
                return (
                  <a
                    key={social.platform}
                    href={social.href}
                    target="_blank"
                    rel="noopener noreferrer"
                    aria-label={social.ariaLabel}
                    className={cn(
                      "p-2 rounded-full transition-colors duration-200",
                      "text-[var(--text-muted)] hover:text-white",
                      "hover:bg-[var(--accent)]"
                    )}
                  >
                    {Icon && <Icon size={18} />}
                  </a>
                );
              })}
            </div>
          </div>

          {/* Link columns */}
          {FOOTER_LINKS.map((group) => (
            <div key={group.heading}>
              <h3 className="font-semibold text-sm text-[var(--text)] mb-4 uppercase tracking-wider">
                {group.heading}
              </h3>
              <ul className="space-y-2.5">
                {group.links.map((link) => (
                  <li key={link.href}>
                    <Link
                      href={link.href}
                      target={link.external ? "_blank" : undefined}
                      rel={link.external ? "noopener noreferrer" : undefined}
                      className="text-sm text-[var(--text-muted)] hover:text-[var(--accent)] transition-colors duration-200"
                    >
                      {link.label}
                    </Link>
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>
      </div>

      {/* Bottom bar */}
      <div className="border-t border-[var(--border)]">
        <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 py-5 flex flex-col sm:flex-row items-center justify-between gap-3 text-xs text-[var(--text-muted)]">
          <p>
            &copy; {year} {CHURCH_INFO.name}. All rights reserved.
          </p>
          <p>
            Built with faith and purpose.
          </p>
        </div>
      </div>
    </footer>
  );
}
